:root {
  --tv-gold: 218, 165, 32;
  --tv-gold-light: 255, 215, 0;
  --tv-gold-dark: 184, 134, 11;
  --tv-black: 28, 28, 28;
  --tv-white: 248, 248, 248;
  --body-font: 'Playfair Display', serif;
  --retro-font: 'Poiret One', cursive;
}

.page-container .page {
  border: 3px solid rgb(var(--tv-gold));
  margin: 12px auto;
  border-radius: 8px;
  box-shadow: 0 0 18px rgba(var(--tv-gold), 0.25), inset 0 0 9px rgba(var(--tv-gold), 0.18);
  background: transparent;
  background-image: repeating-linear-gradient(0deg, rgba(var(--tv-gold-light), 0.025) 0px, transparent 2px, transparent 4px);
}

.theme-fandomdesktop-dark {
  --theme-page-background-color: transparent;
  --theme-page-background-color--secondary: rgba(var(--tv-gold), 0.07);
  --theme-link-color: rgb(248, 248, 248);
  --theme-border-color: rgb(var(--tv-gold));
  --theme-community-header-color: rgb(var(--tv-gold));
  --theme-sticky-nav-background-color: rgba(28, 28, 28, 0.97);
  --theme-sticky-nav-text-color: rgb(255, 215, 0);
  --theme-sticky-nav-text-color--hover: rgb(var(--tv-gold-light));
}

.theme-fandomdesktop-light {
  --theme-page-background-color: rgba(255, 255, 255, 0.96);
  --theme-page-background-color--secondary: transparent;
  --theme-link-color: rgb(40, 40, 40);
  --theme-border-color: rgb(var(--tv-gold));
  --theme-community-header-color: rgb(var(--tv-gold));
  --theme-sticky-nav-background-color: rgba(255, 255, 255, 0.98);
  --theme-sticky-nav-text-color: rgb(28, 28, 28);
  --theme-sticky-nav-text-color--hover: rgb(var(--tv-gold));
}

a, a:visited {
  color: rgb(255, 215, 0) !important;
  text-decoration: none;
  transition: color 0.3s ease, text-shadow 0.3s ease;
}

a:hover, a:focus {
  color: rgb(var(--tv-gold-light)) !important;
  text-shadow: 0 0 5px rgba(var(--tv-gold-light), 0.65), 0 0 10px rgba(var(--tv-gold), 0.45);
}

.page-side-tools .page-side-tool {
  border: 2px solid rgb(var(--tv-gold-light));
  box-shadow: 0 0 9px rgba(var(--tv-gold), 0.35);
  border-radius: 50%;
  background-color: rgba(var(--tv-black), 0.94);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.page-side-tool:hover {
  transform: scale(1.07);
  box-shadow: 0 0 16px rgba(var(--tv-gold), 0.65);
}

.titleblock, .dark-titleblock {
  background: radial-gradient(circle at top, rgba(var(--tv-gold-light), 0.12), rgba(var(--tv-black), 0.97));
  border: 3px solid rgb(var(--tv-gold));
  border-radius: 8px;
  padding: 1.1rem;
  font-family: var(--retro-font);
  font-weight: 400;
  color: rgb(var(--tv-gold-light));
  text-shadow: 0 0 5px rgba(var(--tv-gold-light), 0.65), 0 0 11px rgba(var(--tv-gold), 0.45);
  font-size: 2.4em;
  letter-spacing: 4px;
  transform: rotate(-0.4deg);
  animation: subtle-glow 5s infinite alternate;
}

.progress {
  background: rgba(var(--tv-black), 0.97);
  border: 2px solid rgb(var(--tv-gold));
  border-radius: 8px;
  color: rgb(var(--tv-white));
  box-shadow: 0 0 9px rgba(var(--tv-gold), 0.35);
}

.progress .bar {
  background: linear-gradient(to right, rgb(var(--tv-gold)), rgb(var(--tv-gold-light)));
  border-radius: 6px;
  box-shadow: 0 0 13px rgba(var(--tv-gold-light), 0.55);
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--retro-font);
  color: rgb(var(--tv-gold-light));
  text-transform: uppercase;
  letter-spacing: 6px;
  text-shadow: 0 0 6px rgba(var(--tv-gold-light), 0.65), 0 0 13px rgba(var(--tv-gold), 0.5);
  font-size: calc(1.5rem + 0.7vw);
}

h1 {
  font-size: calc(2.2rem + 1.1vw);
}

@keyframes subtle-glow {
  0%, 100% {
    opacity: 1;
    text-shadow: 0 0 6px rgba(var(--tv-gold-light), 0.75), 0 0 14px rgba(var(--tv-gold), 0.55);
  }
  50% {
    opacity: 0.94;
    text-shadow: 0 0 4px rgba(var(--tv-gold-light), 0.5), 0 0 9px rgba(var(--tv-gold), 0.35);
  }
}
}}
